+// ============================================================================
+// GGUF Layer Reader - For Q-Healing layer-by-layer tensor access
+// ============================================================================
+
+/// GGUF file reader for layer-by-layer tensor access
+/// Does NOT load the entire model - only reads specific tensors on demand
+pub const GGUFReader = struct {
+    allocator: std.mem.Allocator,
+    path: []const u8,
+    file: std.fs.File,
+    ctx: *c.gguf_context,
+    data_offset: usize,
+    n_tensors: i64,
+
+    const Self = @This();
+
+    /// Open a GGUF file for layer-by-layer reading
+    /// This only parses metadata - no tensor data is loaded yet
+    pub fn open(allocator: std.mem.Allocator, path: []const u8) !Self {
+        // Create null-terminated path for C API
+        const path_z = try allocator.dupeZ(u8, path);
+        defer allocator.free(path_z);
+
+        // Initialize GGUF context without loading tensor data
+        const init_params = c.gguf_init_params{
+            .no_alloc = true, // Don't allocate tensor data
+            .ctx = null, // Don't create ggml context
+        };
+
+        const ctx = c.gguf_init_from_file(path_z.ptr, init_params);
+        if (ctx == null) {
+            return error.FailedToOpenGGUF;
+        }
+        errdefer c.gguf_free(ctx.?);
+
+        // Open file for direct tensor reading
+        const file = try std.fs.cwd().openFile(path, .{});
+        errdefer file.close();
+
+        // Disable macOS file caching to prevent RAM pressure from large files
+        // F_NOCACHE tells the kernel not to cache this file's data
+        if (@import("builtin").os.tag == .macos) {
+            const fd = file.handle;
+            _ = std.c.fcntl(fd, std.c.F.NOCACHE, @as(c_int, 1));
+        }
+
+        const path_copy = try allocator.dupe(u8, path);
+        errdefer allocator.free(path_copy);
+
+        return Self{
+            .allocator = allocator,
+            .path = path_copy,
+            .file = file,
+            .ctx = ctx.?,
+            .data_offset = c.gguf_get_data_offset(ctx.?),
+            .n_tensors = c.gguf_get_n_tensors(ctx.?),
+        };
+    }
+
+    pub fn close(self: *Self) void {
+        c.gguf_free(self.ctx);
+        self.file.close();
+        self.allocator.free(self.path);
+    }
+
+    /// Get the number of tensors in the file
+    pub fn getTensorCount(self: *const Self) u64 {
+        return @intCast(self.n_tensors);
+    }
+
+    /// Find tensor by name pattern (e.g., "blk.5.attn_q.weight")
+    /// Returns tensor index or null if not found
+    pub fn findTensor(self: *const Self, name: []const u8) ?i64 {
+        var name_buf: [256]u8 = undefined;
+        if (name.len >= name_buf.len) return null;
+        @memcpy(name_buf[0..name.len], name);
+        name_buf[name.len] = 0;
+
+        const idx = c.gguf_find_tensor(self.ctx, &name_buf);
+        if (idx < 0) return null;
+        return idx;
+    }
+
+    /// Get tensor name by index
+    pub fn getTensorName(self: *const Self, tensor_idx: i64) ?[]const u8 {
+        const name_ptr = c.gguf_get_tensor_name(self.ctx, tensor_idx);
+        if (name_ptr == null) return null;
+        return std.mem.span(name_ptr);
+    }
+
+    /// Get tensor size in bytes
+    pub fn getTensorSize(self: *const Self, tensor_idx: i64) usize {
+        return c.gguf_get_tensor_size(self.ctx, tensor_idx);
+    }
+
+    /// Get tensor data type
+    pub fn getTensorType(self: *const Self, tensor_idx: i64) c_uint {
+        return @intFromEnum(c.gguf_get_tensor_type(self.ctx, tensor_idx));
+    }
+
+    /// Read tensor data from disk into provided buffer
+    /// This is the core operation for layer-by-layer loading
+    pub fn readTensorData(self: *Self, tensor_idx: i64, buffer: []u8) !usize {
+        const offset = c.gguf_get_tensor_offset(self.ctx, tensor_idx);
+        const size = c.gguf_get_tensor_size(self.ctx, tensor_idx);
+
+        if (buffer.len < size) {
+            return error.BufferTooSmall;
+        }
+
+        // Seek to tensor data position
+        const absolute_offset = self.data_offset + offset;
+        try self.file.seekTo(absolute_offset);
+
+        // Read tensor data
+        const bytes_read = try self.file.readAll(buffer[0..size]);
+        if (bytes_read != size) {
+            return error.IncompleteRead;
+        }
+
+        return size;
+    }
+
+    /// Allocate and read tensor data
+    /// Caller owns returned memory
+    pub fn readTensorAlloc(self: *Self, tensor_idx: i64) ![]align(64) u8 {
+        const size = c.gguf_get_tensor_size(self.ctx, tensor_idx);
+
+        // Allocate aligned buffer for SIMD operations
+        const buffer = try self.allocator.alignedAlloc(u8, 64, size);
+        errdefer self.allocator.free(buffer);
+
+        _ = try self.readTensorData(tensor_idx, buffer);
+
+        return buffer;
+    }
+
+    /// Find all tensors for a specific layer
+    /// Returns list of tensor indices for layer N (e.g., "blk.N.*")
+    pub fn findLayerTensors(self: *const Self, allocator: std.mem.Allocator, layer_idx: u32) ![]i64 {
+        var indices = std.ArrayList(i64).init(allocator);
+        errdefer indices.deinit();
+
+        // Build layer prefix (e.g., "blk.5.")
+        var prefix_buf: [32]u8 = undefined;
+        const prefix = std.fmt.bufPrint(&prefix_buf, "blk.{d}.", .{layer_idx}) catch return error.FormatError;
+
+        // Scan all tensors for matches
+        var i: i64 = 0;
+        while (i < self.n_tensors) : (i += 1) {
+            if (self.getTensorName(i)) |name| {
+                if (std.mem.startsWith(u8, name, prefix)) {
+                    try indices.append(i);
+                }
+            }
+        }
+
+        return indices.toOwnedSlice();
+    }
+
+    /// Get total size of all tensors in a layer
+    pub fn getLayerTotalSize(self: *const Self, allocator: std.mem.Allocator, layer_idx: u32) !usize {
+        const tensor_indices = try self.findLayerTensors(allocator, layer_idx);
+        defer allocator.free(tensor_indices);
+
+        var total: usize = 0;
+        for (tensor_indices) |idx| {
+            total += self.getTensorSize(idx);
+        }
+        return total;
+    }
+};

