+/// Auto-detect reference model for Q-Healing (zero-config)
+/// Looks for higher-precision versions of the same model in the same directory
+/// e.g., model-Q2_K.gguf -> looks for model-Q8_0.gguf, model-fp16.gguf
+/// Memory-aware: skips models too large for available RAM
+fn detectReferenceModel(allocator: std.mem.Allocator, model_path: []const u8) ![]const u8 {
+    const dirname = std.fs.path.dirname(model_path) orelse ".";
+    const basename = std.fs.path.basename(model_path);
+
+    // Extract model name without quantization suffix
+    // Pattern: name-Q2_K.gguf, name_Q2_K.gguf, name-q2_k.gguf
+    const quant_patterns = [_][]const u8{
+        "-Q2_K.gguf",
+        "_Q2_K.gguf",
+        "-q2_k.gguf",
+        "_q2_k.gguf",
+        "-Q3_K_S.gguf",
+        "-Q3_K_M.gguf",
+        "-Q4_K_S.gguf",
+        "-Q4_K_M.gguf",
+        "-q3_k_s.gguf",
+        "-q3_k_m.gguf",
+        "-q4_k_s.gguf",
+        "-q4_k_m.gguf",
+    };
+
+    var model_base: ?[]const u8 = null;
+    for (quant_patterns) |pattern| {
+        if (std.mem.endsWith(u8, basename, pattern)) {
+            model_base = basename[0 .. basename.len - pattern.len];
+            break;
+        }
+    }
+
+    // If no quantization pattern found, can't detect reference
+    const base = model_base orelse return error.NoQuantizationPattern;
+
+    // Look for higher-precision versions (Q8_0, Q6_K, Q5_K_M, fp16)
+    // Ordered by preference (Q8_0 is best reference quality)
+    const reference_suffixes = [_][]const u8{
+        "-Q8_0.gguf",
+        "_Q8_0.gguf",
+        "-q8_0.gguf",
+        "_q8_0.gguf",
+        "-Q6_K.gguf",
+        "-q6_k.gguf",
+        "-Q5_K_M.gguf",
+        "-q5_k_m.gguf",
+        "-Q4_K_M.gguf", // Use Q4 as fallback reference if Q2 runtime
+        "-q4_k_m.gguf",
+        "-fp16.gguf",
+        "_fp16.gguf",
+        "-FP16.gguf",
+        "_FP16.gguf",
+        "-f16.gguf",
+        "_f16.gguf",
+        "-F16.gguf",
+        "_F16.gguf",
+    };
+
+    for (reference_suffixes) |suffix| {
+        const candidate = try std.fmt.allocPrint(allocator, "{s}/{s}{s}", .{ dirname, base, suffix });
+        errdefer allocator.free(candidate);
+
+        // Check if this file exists
+        std.fs.cwd().access(candidate, .{}) catch {
+            allocator.free(candidate);
+            continue;
+        };
+
+        // Found a reference model (layer-by-layer loading handles any size)
+        return candidate;
+    }
+
+    return error.NoReferenceModelFound;
+}
