+const std = @import("std");
+const llama = @import("llama.zig");
+const Scheduler = @import("scheduler.zig").Scheduler;
+const logger = @import("logger.zig");
+
+/// Server configuration
+pub const ServerConfig = struct {
+    host: []const u8 = "127.0.0.1",
+    port: u16 = 11434,
+    request_timeout_ms: u32 = 300_000, // 5 min
+};
+
+/// HTTP Server for OpenAI-compatible API
+pub const Server = struct {
+    allocator: std.mem.Allocator,
+    config: ServerConfig,
+    model: *llama.Model,
+    model_name: []const u8,
+    scheduler: *Scheduler,
+    running: std.atomic.Value(bool),
+    tcp_server: ?std.net.Server,
+
+    const Self = @This();
+
+    pub fn init(
+        allocator: std.mem.Allocator,
+        model: *llama.Model,
+        model_name: []const u8,
+        scheduler: *Scheduler,
+        config: ServerConfig,
+    ) Self {
+        return Self{
+            .allocator = allocator,
+            .config = config,
+            .model = model,
+            .model_name = model_name,
+            .scheduler = scheduler,
+            .running = std.atomic.Value(bool).init(false),
+            .tcp_server = null,
+        };
+    }
+
+    pub fn deinit(self: *Self) void {
+        self.stop();
+        if (self.tcp_server) |*srv| {
+            srv.deinit();
+        }
+    }
+
+    pub fn stop(self: *Self) void {
+        self.running.store(false, .release);
+    }
+
+    /// Start the HTTP server and block until stopped
+    pub fn start(self: *Self) !void {
+        const address = try std.net.Address.parseIp4(self.config.host, self.config.port);
+        self.tcp_server = try address.listen(.{
+            .reuse_address = true,
+        });
+
+        self.running.store(true, .release);
+
+        std.debug.print("\n🚀 Zell server running on http://{s}:{d}\n", .{ self.config.host, self.config.port });
+        std.debug.print("   Model: {s}\n", .{self.model_name});
+        std.debug.print("   Press Ctrl+C to stop\n\n", .{});
+
+        while (self.running.load(.acquire)) {
+            // Accept connection
+            const conn = self.tcp_server.?.accept() catch |err| {
+                if (err == error.WouldBlock) continue;
+                logger.err("Accept error: {}", .{err});
+                continue;
+            };
+
+            self.handleConnection(conn.stream) catch |err| {
+                logger.err("Connection error: {}", .{err});
+            };
+            conn.stream.close();
+        }
+    }
+
+    fn handleConnection(self: *Self, stream: std.net.Stream) !void {
+        // Read HTTP request (simple parsing)
+        var read_buffer: [8192]u8 = undefined;
+        const bytes_read = try stream.read(&read_buffer);
+        if (bytes_read == 0) return;
+
+        const request = read_buffer[0..bytes_read];
+
+        // Parse first line to get method and path
+        const first_line_end = std.mem.indexOf(u8, request, "\r\n") orelse return;
+        const first_line = request[0..first_line_end];
+
+        // Parse "METHOD /path HTTP/1.1"
+        var parts = std.mem.splitScalar(u8, first_line, ' ');
+        const method = parts.next() orelse return;
+        const path = parts.next() orelse return;
+
+        // Find body (after \r\n\r\n)
+        const body_start = std.mem.indexOf(u8, request, "\r\n\r\n");
+        const body = if (body_start) |bs| request[bs + 4 ..] else "";
+
+        // Route to handler
+        if (std.mem.startsWith(u8, path, "/v1/chat/completions")) {
+            try self.handleChatCompletions(stream, method, body);
+        } else if (std.mem.startsWith(u8, path, "/v1/models")) {
+            try self.handleModels(stream);
+        } else if (std.mem.startsWith(u8, path, "/health")) {
+            try self.handleHealth(stream);
+        } else if (std.mem.eql(u8, path, "/")) {
+            try self.handleRoot(stream);
+        } else {
+            try self.sendError(stream, 404, "Not Found");
+        }
+    }
+
+    fn sendResponse(self: *Self, stream: std.net.Stream, status: u16, body: []const u8) !void {
+        _ = self;
+        const status_text = switch (status) {
+            200 => "OK",
+            400 => "Bad Request",
+            404 => "Not Found",
+            405 => "Method Not Allowed",
+            500 => "Internal Server Error",
+            503 => "Service Unavailable",
+            else => "Unknown",
+        };
+
+        var header_buf: [512]u8 = undefined;
+        const header = try std.fmt.bufPrint(&header_buf,
+            "HTTP/1.1 {d} {s}\r\n" ++
+                "Content-Type: application/json\r\n" ++
+                "Content-Length: {d}\r\n" ++
+                "Connection: close\r\n" ++
+                "\r\n",
+            .{ status, status_text, body.len },
+        );
+
+        _ = try stream.write(header);
+        _ = try stream.write(body);
+    }
+
+    fn handleRoot(self: *Self, stream: std.net.Stream) !void {
+        const body =
+            \\{"status":"ok","name":"zell","version":"0.1.0"}
+        ;
+        try self.sendResponse(stream, 200, body);
+    }
+
+    fn handleHealth(self: *Self, stream: std.net.Stream) !void {
+        try self.sendResponse(stream, 200, "{\"status\":\"ok\"}");
+    }
+
+    fn handleModels(self: *Self, stream: std.net.Stream) !void {
+        var buffer: [2048]u8 = undefined;
+        const response = try std.fmt.bufPrint(&buffer,
+            \\{{"object":"list","data":[{{"id":"{s}","object":"model","owned_by":"local"}}]}}
+        , .{self.model_name});
+
+        try self.sendResponse(stream, 200, response);
+    }
+
+    fn handleChatCompletions(self: *Self, stream: std.net.Stream, method: []const u8, body: []const u8) !void {
