+        for (chat_req.messages) |msg| {
+            if (std.mem.eql(u8, msg.role, "system")) {
+                try prompt_builder.appendSlice(self.allocator, "<|im_start|>system\n");
+                try prompt_builder.appendSlice(self.allocator, msg.content);
+                try prompt_builder.appendSlice(self.allocator, "<|im_end|>\n");
+            } else if (std.mem.eql(u8, msg.role, "user")) {
+                try prompt_builder.appendSlice(self.allocator, "<|im_start|>user\n");
+                try prompt_builder.appendSlice(self.allocator, msg.content);
+                try prompt_builder.appendSlice(self.allocator, "<|im_end|>\n");
+            } else if (std.mem.eql(u8, msg.role, "assistant")) {
+                try prompt_builder.appendSlice(self.allocator, "<|im_start|>assistant\n");
+                try prompt_builder.appendSlice(self.allocator, msg.content);
+                try prompt_builder.appendSlice(self.allocator, "<|im_end|>\n");
+            }
+        }
