+
+        // Find idle cell and submit
+        const cell_id = self.scheduler.findIdleCell() orelse {
+            try self.sendError(stream, 503, "Server busy");
+            return;
+        };
+
+        // Reset cell for new request
+        self.scheduler.cells[cell_id].reset();
+
+        // Submit prompt
+        self.scheduler.submit(cell_id, prompt, max_tokens, null) catch |err| {
+            logger.err("Submit error: {}", .{err});
+            try self.sendError(stream, 500, "Failed to process request");
+            return;
+        };
+
+        // Run generation loop
+        var iterations: u32 = 0;
+        const max_iterations = max_tokens * 2 + 1000; // Safety limit
+        while (iterations < max_iterations) : (iterations += 1) {
+            const active = self.scheduler.step() catch |err| {
+                logger.err("Step error: {}", .{err});
+                break;
+            };
+            if (!active) break;
+        }
+
+        // Get output
+        const cell = &self.scheduler.cells[cell_id];
+        const output = cell.getOutput();
+        const generated_tokens = cell.generated_count;
+
+        // Build response
+        const response = try self.buildChatResponse(output, generated_tokens, prompt.len);
+        defer self.allocator.free(response);
+
+        try self.sendResponse(stream, 200, response);
+
+        logger.info("Generated {} tokens", .{generated_tokens});
+    }
+
+    fn buildChatResponse(self: *Self, content: []const u8, completion_tokens: u32, prompt_len: usize) ![]u8 {
+        // Escape content for JSON
