+        return try std.fmt.allocPrint(self.allocator,
+            \\{{"id":"{s}","object":"chat.completion","created":{d},"model":"{s}","choices":[{{"index":0,"message":{{"role":"assistant","content":"{s}"}},"finish_reason":"stop"}}],"usage":{{"prompt_tokens":{d},"completion_tokens":{d},"total_tokens":{d}}}}}
+        , .{
+            id,
+            timestamp,
+            self.model_name,
+            escaped.items,
+            prompt_tokens,
+            completion_tokens,
+            prompt_tokens + completion_tokens,
+        });
+    }
+
+    fn sendError(self: *Self, stream: std.net.Stream, status: u16, message: []const u8) !void {
+        var buffer: [512]u8 = undefined;
+        const body = try std.fmt.bufPrint(&buffer,
+            \\{{"error":{{"message":"{s}","type":"error"}}}}
+        , .{message});
+
+        try self.sendResponse(stream, status, body);
+    }
+};
